    34	
    35	async function validateApiToken(token: string): Promise<{
    36	  userId: string;
    37	  workspaceId: string | null;
    38	  isSuperAdmin: boolean;
    39	  tokenId: string;
    40	} | null> {
    41	  const result = await pool.query(
    42	    `SELECT t.id, t.user_id, t.workspace_id, t.expires_at, t.revoked_at, u.is_super_admin
    43	     FROM api_tokens t
    44	     JOIN users u ON t.user_id = u.id
    45	     WHERE t.token_hash = $1
    46	     LIMIT 1`,
    47	    [hashToken(token)]
    48	  );
    49	
    50	  const tokenRow = result.rows[0];
    51	  if (!tokenRow || tokenRow.revoked_at || (tokenRow.expires_at && new Date(tokenRow.expires_at) <= new Date())) {
    52	    return null;
    53	  }
    54	
    55	  await pool.query('UPDATE api_tokens SET last_used_at = NOW() WHERE id = $1', [tokenRow.id]);
    56	
