    93	  if (!sessionId) {
    94	    sendAuthError(res, HTTP_STATUS.UNAUTHORIZED, ERROR_CODES.UNAUTHORIZED, 'No session found');
    95	    return;
    96	  }
    97	
    98	  try {
    99	    const result = await pool.query(
   100	      `SELECT s.id, s.user_id, s.workspace_id, s.last_activity, s.created_at, u.is_super_admin
   101	       FROM sessions s
   102	       JOIN users u ON s.user_id = u.id
   103	       WHERE s.id = $1
