   128	      const membershipResult = await pool.query(
   129	        'SELECT 1 FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2 LIMIT 1',
   130	        [session.workspace_id, session.user_id]
   131	      );
   132	      if (!membershipResult.rows[0]) {
   133	        await pool.query('DELETE FROM sessions WHERE id = $1', [sessionId]);
   134	        sendAuthError(res, HTTP_STATUS.FORBIDDEN, ERROR_CODES.FORBIDDEN, 'Access to this workspace has been revoked');
   135	        return;
   136	      }
   137	    }
   138	
   139	    await pool.query('UPDATE sessions SET last_activity = NOW() WHERE id = $1', [sessionId]);
   140	    if (now.getTime() - lastActivity.getTime() > COOKIE_REFRESH_THRESHOLD_MS) {
   141	      res.cookie('session_id', sessionId, SESSION_COOKIE_OPTIONS);
   142	    }
