    59	/**
    60	 * InlineCommentThread component rendered inside widget decorations.
    61	 * Displays a GitHub-style comment card that breaks the document flow.
    62	 */
    63	function InlineCommentThread({
    64	  thread,
    65	  quotedText,
    66	}: {
    67	  thread: Comment[];
    68	  quotedText: string;
    69	}) {
    70	  const root = thread[0];
    71	  const replies = thread.slice(1);
    72	  const isResolved = root.resolved_at !== null;
    73	
    74	  const container = document.createElement('div');
    75	
    76	  // Create a simple DOM structure (no React inside decorations for simplicity)
    77	  container.className = 'comment-thread-inline';
    78	  container.setAttribute('data-comment-thread', root.comment_id);
    79	  container.contentEditable = 'false';
    80	
    81	  if (isResolved) {
    82	    container.innerHTML = `
    83	      <div class="comment-thread-resolved" data-comment-id="${escapeHtml(root.comment_id)}">
    84	        <span class="comment-resolved-icon">✓</span>
    85	        <span class="comment-resolved-text">Resolved by ${escapeHtml(root.author.name)} · ${formatRelativeTime(root.resolved_at!)}</span>
    86	        <span class="comment-resolved-toggle">Show thread</span>
    87	      </div>
    88	    `;
    89	  } else {
    90	    const quotedHtml = quotedText
    91	      ? `<div class="comment-quoted-text">"${escapeHtml(quotedText)}"</div>`
    92	      : '';
    93	
    94	    let repliesHtml = '';
    95	    for (const reply of replies) {
    96	      repliesHtml += `
    97	        <div class="comment-reply">
    98	          <div class="comment-header">
    99	            <span class="comment-author">${escapeHtml(reply.author.name)}</span>
   100	            <span class="comment-time">${formatRelativeTime(reply.created_at)}</span>
   101	          </div>
   102	          <div class="comment-body">${escapeHtml(reply.content)}</div>
   103	        </div>
   104	      `;
   105	    }
   106	
   107	    container.innerHTML = `
   108	      ${quotedHtml}
   109	      <div class="comment-root">
   110	        <div class="comment-header">
   111	          <span class="comment-author">${escapeHtml(root.author.name)}</span>
   112	          <span class="comment-time">${formatRelativeTime(root.created_at)}</span>
   113	          <button class="comment-resolve-btn" data-comment-id="${escapeHtml(root.comment_id)}" title="Resolve">✓</button>
   114	        </div>
   115	        <div class="comment-body">${escapeHtml(root.content)}</div>
   116	      </div>
   117	      ${repliesHtml}
   118	      <div class="comment-reply-area">
   119	        <input type="text" class="comment-reply-input" placeholder="Reply..." data-comment-id="${escapeHtml(root.comment_id)}" />
   120	      </div>
   121	    `;
   122	  }
   123	
   124	  return container;
   125	}
