   390	/**
   391	 * Generate a presigned URL for S3 PUT upload
   392	 * @param s3Key - The S3 object key (path within bucket)
   393	 * @param contentType - The MIME type of the file being uploaded
   394	 * @param sizeBytes - The expected file size in bytes
   395	 * @returns Presigned URL valid for 15 minutes
   396	 */
   397	async function generateS3PresignedUrl(s3Key: string, contentType: string, sizeBytes: number): Promise<string> {
   398	  if (!S3_BUCKET_NAME) {
   399	    throw new Error('S3_UPLOADS_BUCKET environment variable is not configured');
   400	  }
   401	
   402	  const client = getS3Client();
   403	  const command = new PutObjectCommand({
   404	    Bucket: S3_BUCKET_NAME,
   405	    Key: s3Key,
   406	    ContentType: contentType,
   407	    ContentLength: sizeBytes,
   408	  });
   409	
   410	  const presignedUrl = await getSignedUrl(client, command, {
   411	    expiresIn: PRESIGNED_URL_EXPIRES_IN,
   412	  });
   413	
   414	  return presignedUrl;
   415	}
