     5	import { createContext, useContext, useEffect, ReactNode, useSyncExternalStore } from 'react';
     6	import {
     7	  getUploadCount,
     8	  subscribeToUploads,
     9	} from '@/services/uploadTracker';
    10	
    11	interface UploadContextValue {
    12	  uploadCount: number;
    13	  isUploading: boolean;
    14	}
    15	
    16	const UploadContext = createContext<UploadContextValue | null>(null);
    17	
    18	export function UploadProvider({ children }: { children: ReactNode }) {
    19	  // Subscribe to global upload tracker using useSyncExternalStore
    20	  const uploadCount = useSyncExternalStore(
    21	    subscribeToUploads,
    22	    getUploadCount,
    23	    getUploadCount
    24	  );
    25	
    26	  const isUploading = uploadCount > 0;
    27	
    28	  // Browser beforeunload warning
    29	  useEffect(() => {
    30	    if (!isUploading) return;
    31	
    32	    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
    33	      e.preventDefault();
    34	      // Modern browsers ignore custom messages but still show a generic warning
    35	      e.returnValue = `You have ${uploadCount} upload(s) in progress. Leaving will cancel them.`;
    36	      return e.returnValue;
    37	    };
    38	
    39	    window.addEventListener('beforeunload', handleBeforeUnload);
    40	    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
    41	  }, [isUploading, uploadCount]);
    42	
    43	  return (
    44	    <UploadContext.Provider
    45	      value={{
    46	        uploadCount,
    47	        isUploading,
    48	      }}
    49	    >
    50	      {children}
    51	    </UploadContext.Provider>
    52	  );
    53	}
    54	
    55	export function useUploads() {
    56	  const context = useContext(UploadContext);
    57	  if (!context) {
    58	    throw new Error('useUploads must be used within an UploadProvider');
    59	  }
    60	  return context;
    61	}
    62	
    63	/**
    64	 * Hook for checking upload status
    65	 * Note: In-app SPA navigation blocking requires migrating to createBrowserRouter.
    66	 * Currently we only block browser navigation via beforeunload.
    67	 */
    68	export function useUploadNavigationWarning() {
    69	  const { isUploading, uploadCount } = useUploads();
    70	
    71	  return {
    72	    isBlocked: false, // Disabled until we migrate to data router
    73	    uploadCount,
    74	    proceed: () => {},
    75	    reset: () => {},
    76	  };
    77	}
