{"success":true,"content":"     1	/**
     2	 * File upload service for images and attachments.
     3	 * Handles upload flow: get presigned URL -> upload to storage -> confirm -> return CDN URL
     4	 */
     5	
     6	// In development, Vite proxy handles /api routes (see vite.config.ts)
     7	// In production, use VITE_API_URL or relative URLs
     8	const API_BASE = import.meta.env.VITE_API_URL ?? '';
     9	
    10	// File size limits
    11	export const MAX_FILE_SIZE = 1073741824; // 1GB in bytes
    12	export const MAX_FILE_SIZE_DISPLAY = '1GB';
    13	
    14	interface UploadResult {
    15	  fileId: string;
    16	  cdnUrl: string;
    17	}
    18	
    19	interface UploadProgress {
    20	  fileId: string;
    21	  progress: number; // 0-100
    22	  status: 'pending' | 'uploading' | 'confirming' | 'complete' | 'error';
    23	  error?: string;
    24	}
    25	
    26	type ProgressCallback = (progress: UploadProgress) => void;
    27	
    28	/**
    29	 * Get CSRF token for API requests
    30	 */
    31	async function getCsrfToken(): Promise<string> {
    32	  const res = await fetch(`${API_BASE}/api/csrf-token`, { credentials: 'include' });
    33	  if (!res.ok) throw new Error('Failed to get CSRF token');
    34	  const { token } = await res.json();
    35	  return token;
    36	}
    37	
    38	/**
    39	 * Upload a file to the server
    40	 * @param file - The file to upload
    41	 * @param onProgress - Optional callback for progress updates
    42	 * @param signal - Optional AbortSignal for cancelling the upload
    43	 * @returns The CDN URL of the uploaded file
    44	 */
    45	export async function uploadFile(
    46	  file: File,
    47	  onProgress?: ProgressCallback,
    48	  signal?: AbortSignal
    49	): Promise<UploadResult> {
    50	  // Check if already aborted
    51	  if (signal?.aborted) {
    52	    throw new DOMException('Upload cancelled', 'AbortError');
    53	  }
    54	
    55	  const csrfToken = await getCsrfToken();
    56	
    57	  const progress: UploadProgress = {
    58	    fileId: '',
    59	    progress: 0,
    60	    status: 'pending',
    61	  };
    62	
    63	  const updateProgress = (updates: Partial<UploadProgress>) => {
    64	    Object.assign(progress, updates);
    65	    onProgress?.({ ...progress });
    66	  };
    67	
    68	  try {
    69	    // Step 1: Request upload URL
    70	    updateProgress({ status: 'pending', progress: 10 });
    71	
    72	    // Use effective MIME type (fallback to extension-based detection if browser returns empty)
    73	    const effectiveMimeType = file.type || getMimeTypeFromExtension(file.name) || 'application/octet-stream';
    74	
    75	    const uploadReqRes = await fetch(`${API_BASE}/api/files/upload`, {
    76	      method: 'POST',
    77	      headers: {
    78	        'Content-Type': 'application/json',
    79	        'x-csrf-token': csrfToken,
    80	      },
    81	      credentials: 'include',
    82	      body: JSON.stringify({
    83	        filename: file.name,
    84	        mimeType: effectiveMimeType,
    85	        sizeBytes: file.size,
    86	      }),
    87	      signal,
    88	    });
    89	
    90	    if (!uploadReqRes.ok) {
    91	      const error = await uploadReqRes.json();
    92	      throw new Error(error.error || 'Failed to create upload request');
    93	    }
    94	
    95	    const { fileId, uploadUrl, s3Key } = await uploadReqRes.json();
    96	    updateProgress({ fileId, progress: 20 });
    97	
    98	    // Step 2: Upload file data
    99	    updateProgress({ status: 'uploading', progress: 30 });
   100	
   101	    // Check if this is a local upload URL or S3 presigned URL
   102	    const isLocalUpload = uploadUrl.startsWith('/api/files/');
   103	    const fullUploadUrl = isLocalUpload ? `${API_BASE}${uploadUrl}` : uploadUrl;
   104	
   105	    const fileBuffer = await file.arrayBuffer();
   106	
   107	    if (isLocalUpload) {
   108	      // Local development: upload to our API
   109	      const uploadRes = await fetch(fullUploadUrl, {
   110	        method: 'POST',
   111	        headers: {
   112	          'x-csrf-token': csrfToken,
   113	          'Content-Type': effectiveMimeType,
   114	        },
   115	        credentials: 'include',
   116	        body: fileBuffer,
   117	        signal,
   118	      });
   119	
   120	      if (!uploadRes.ok) {
   121	        const error = await uploadRes.json();
   122	        throw new Error(error.error || 'Failed to upload file');
   123	      }
   124	
   125	      updateProgress({ progress: 90 });
   126	
   127	      // For local uploads, the local-upload endpoint already sets status to 'uploaded'
   128	      // Just get the file metadata to return the CDN URL
   129	      const fileRes = await fetch(`${API_BASE}/api/files/${fileId}`, {
   130	        credentials: 'include',
   131	        signal,
   132	      });
   133	
   134	      if (!fileRes.ok) {
   135	        throw new Error('Failed to get file metadata');
   136	      }
   137	
   138	      const fileData = await fileRes.json();
   139	      updateProgress({ status: 'complete', progress: 100 });
   140	
   141	      return {
   142	        fileId,
   143	        cdnUrl: fileData.cdn_url,
   144	      };
   145	    } else {
   146	      // Production: upload directly to S3
   147	      const uploadRes = await fetch(fullUploadUrl, {
   148	        method: 'PUT',
   149	        headers: {
   150	          'Content-Type': effectiveMimeType,
   151	        },
   152	        body: fileBuffer,
   153	        signal,
   154	      });
   155	
   156	      if (!uploadRes.ok) {
   157	        throw new Error('Failed to upload to S3');
   158	      }
   159	
   160	      updateProgress({ status: 'confirming', progress: 80 });
   161	
   162	      // Step 3: Confirm upload
   163	      const confirmRes = await fetch(`${API_BASE}/api/files/${fileId}/confirm`, {
   164	        method: 'POST',
   165	        headers: {
   166	          'x-csrf-token': csrfToken,
   167	        },
   168	        credentials: 'include',
   169	        signal,
   170	      });
   171	
   172	      if (!confirmRes.ok) {
   173	        const error = await confirmRes.json();
   174	        throw new Error(error.error || 'Failed to confirm upload');
   175	      }
   176	
   177	      const { cdnUrl } = await confirmRes.json();
   178	      updateProgress({ status: 'complete', progress: 100 });
   179	
   180	      return { fileId, cdnUrl };
   181	    }
   182	  } catch (error) {
   183	    updateProgress({
   184	      status: 'error',
   185	      error: error instanceof Error ? error.message : 'Upload failed',
   186	    });
   187	    throw error;
   188	  }
   189	}
