   192	 * Upload a file from a data URL (e.g., from clipboard paste)
   193	 */
   194	export async function uploadDataUrl(
   195	  dataUrl: string,
   196	  filename: string,
   197	  onProgress?: ProgressCallback
   198	): Promise<UploadResult> {
   199	  // Convert data URL to File
   200	  const res = await fetch(dataUrl);
   201	  const blob = await res.blob();
   202	  const file = new File([blob], filename, { type: blob.type });
   203	
   204	  return uploadFile(file, onProgress);
   205	}
