    99	
   100	  function traverse(node: JSONContent) {
   101	    if (node.type === 'mention' && node.attrs?.mentionType === 'document' && node.attrs?.id) {
   102	      mentionIds.push(node.attrs.id);
   103	    }
   104	    if (node.content) {
   105	      for (const child of node.content) {
   106	        traverse(child);
   107	      }
   108	    }
   109	  }
   110	
   111	  traverse(content);
   112	  return [...new Set(mentionIds)]; // Deduplicate
   113	}
   114	
   115	// Extract hypothesis text from hypothesisBlock node in TipTap JSON content
   116	function extractHypothesisText(content: JSONContent): string | null {
   117	  let hypothesisText: string | null = null;
   118	
   119	  function traverse(node: JSONContent) {
   120	    if (node.type === 'hypothesisBlock') {
   121	      // Extract plain text from hypothesis block content
   122	      const textParts: string[] = [];
   123	      const extractText = (n: JSONContent) => {
   124	        if (n.type === 'text' && n.text) {
   125	          textParts.push(n.text);
   126	        }
   127	        if (n.content) {
   128	          for (const child of n.content) {
   129	            extractText(child);
   130	          }
   131	        }
   132	      };
   133	      if (node.content) {
   134	        for (const child of node.content) {
   135	          extractText(child);
   136	        }
   137	      }
   138	      hypothesisText = textParts.join('');
   139	      return; // Stop after first hypothesis block
   140	    }
   141	    if (node.content) {
