 * File upload service for images and attachments.
 * Handles upload flow: get presigned URL -> upload to storage -> confirm -> return CDN URL
 */

// In development, Vite proxy handles /api routes (see vite.config.ts)
// In production, use VITE_API_URL or relative URLs
const API_BASE = import.meta.env.VITE_API_URL ?? '';

// File size limits
export const MAX_FILE_SIZE = 1073741824; // 1GB in bytes
export const MAX_FILE_SIZE_DISPLAY = '1GB';

export interface UploadResult {
  fileId: string;
  cdnUrl: string;
}

export interface UploadRequest {
  fileId: string;
  uploadUrl: string;
  method: 'PUT' | 'POST';
  headers?: Record<string, string>;
  uploadType: 's3' | 'local';
}

export interface UploadProgress {
  fileId: string;
  progress: number; // 0-100
  status: 'pending' | 'uploading' | 'confirming' | 'complete' | 'error';
  error?: string;
}

export type ProgressCallback = (progress: UploadProgress) => void;

/**
 * Get CSRF token for API requests
 */
async function getCsrfToken(): Promise<string> {
  const res = await fetch(`${API_BASE}/api/csrf-token`, { credentials: 'include' });
  if (!res.ok) throw new Error('Failed to get CSRF token');
  const { token } = await res.json();
  return token;
}

export async function requestUpload(file: File, signal?: AbortSignal): Promise<UploadRequest> {
  if (signal?.aborted) {
    throw new DOMException('Upload cancelled', 'AbortError');
  }

  const csrfToken = await getCsrfToken();
  const effectiveMimeType = file.type || getMimeTypeFromExtension(file.name) || 'application/octet-stream';
  const res = await fetch(`${API_BASE}/api/files/upload-request`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-csrf-token': csrfToken,
    },
    credentials: 'include',
    body: JSON.stringify({
      filename: file.name,
      mimeType: effectiveMimeType,
      sizeBytes: file.size,
    }),
    signal,
  });

  if (!res.ok) {
    const error = await res.json().catch(() => ({}));
    throw new Error(error.error || 'Failed to create upload request');
  }

  return res.json();
}

export async function uploadFile(
  file: File,
  onProgress?: ProgressCallback,
  signal?: AbortSignal
): Promise<UploadResult> {
  if (signal?.aborted) {
    throw new DOMException('Upload cancelled', 'AbortError');
  }

  const progress: UploadProgress = { fileId: '', progress: 0, status: 'pending' };
  const updateProgress = (updates: Partial<UploadProgress>) => {
    Object.assign(progress, updates);
    onProgress?.({ ...progress });
  };

  try {
    updateProgress({ status: 'pending', progress: 10 });
    const request = await requestUpload(file, signal);
    updateProgress({ fileId: request.fileId, progress: 20 });
    updateProgress({ status: 'uploading', progress: 30 });

    const fileBuffer = await file.arrayBuffer();
    const isLocalUpload = request.uploadType === 'local' || request.uploadUrl.startsWith('/api/files/');
    const fullUploadUrl = request.uploadUrl.startsWith('/api/files/') ? `${API_BASE}${request.uploadUrl}` : request.uploadUrl;

    if (isLocalUpload) {
      const uploadRes = await fetch(fullUploadUrl, {
        method: request.method || 'POST',
        headers: {
          ...(request.headers ?? {}),
          'Content-Type': file.type || getMimeTypeFromExtension(file.name) || 'application/octet-stream',
        },
        credentials: 'include',
        body: fileBuffer,
        signal,
      });

      if (!uploadRes.ok) {
        const error = await uploadRes.json().catch(() => ({}));
        throw new Error(error.error || 'Failed to upload file');
      }

      updateProgress({ progress: 90, status: 'complete' });
      const fileRes = await fetch(`${API_BASE}/api/files/${request.fileId}`, { credentials: 'include', signal });
      if (!fileRes.ok) throw new Error('Failed to get file metadata');
      const fileData = await fileRes.json();
      updateProgress({ progress: 100 });
      return { fileId: request.fileId, cdnUrl: fileData.cdn_url };
    }

    const uploadRes = await fetch(fullUploadUrl, {
      method: request.method || 'PUT',
      headers: {
        ...(request.headers ?? {}),
        'Content-Type': file.type || getMimeTypeFromExtension(file.name) || 'application/octet-stream',
      },
      body: fileBuffer,
      signal,
    });

    if (!uploadRes.ok) {
      throw new Error('Failed to upload to S3');
    }

    updateProgress({ status: 'confirming', progress: 80 });
    const confirmRes = await fetch(`${API_BASE}/api/files/${request.fileId}/confirm`, {
      method: 'POST',
      headers: { 'x-csrf-token': await getCsrfToken() },
      credentials: 'include',
      signal,
    });

    if (!confirmRes.ok) {
      const error = await confirmRes.json().catch(() => ({}));
      throw new Error(error.error || 'Failed to confirm upload');
    }

    const { cdnUrl } = await confirmRes.json();
    updateProgress({ status: 'complete', progress: 100 });
    return { fileId: request.fileId, cdnUrl };
  } catch (error) {
    updateProgress({ status: 'error', error: error instanceof Error ? error.message : 'Upload failed' });
    throw error;
  }
}

/**
 * Upload a file from a data URL (e.g., from clipboard paste)
 */
export async function uploadDataUrl(
  dataUrl: string,
  filename: string,
  onProgress?: ProgressCallback,
  signal?: AbortSignal
): Promise<UploadResult> {
  const res = await fetch(dataUrl);
  const blob = await res.blob();
  const file = new File([blob], filename, { type: blob.type });

  return uploadFile(file, onProgress, signal);
}

/**
 * Blocked file extensions for security (executables and scripts)
 * We allow ANY file type EXCEPT these dangerous extensions.
 * Check by extension, not MIME type (MIME types are unreliable and can be spoofed).
 */
const BLOCKED_EXTENSIONS = new Set([
  // Windows executables
  '.exe', '.bat', '.cmd', '.com', '.msi', '.scr', '.pif',
  // Windows scripts
  '.vbs', '.vbe', '.js', '.jse', '.ws', '.wsf', '.wsc', '.wsh',
  // Windows system files
  '.dll', '.sys', '.drv', '.cpl', '.ocx',
  // Windows shortcuts and config
  '.lnk', '.inf', '.reg', '.msc',
  // macOS executables
  '.app', '.dmg', '.pkg',
  // Linux executables and packages
  '.sh', '.bash', '.deb', '.rpm', '.run',
  // Cross-platform
  '.jar', '.ps1', '.psm1', '.psd1',
]);

/**
 * Map file extensions to MIME types for fallback detection
 * Browsers sometimes return empty MIME type for Office files (especially on macOS)
 */
const EXTENSION_TO_MIME: Record<string, string> = {
  // Images
  '.jpg': 'image/jpeg',
  '.jpeg': 'image/jpeg',
  '.png': 'image/png',
  '.gif': 'image/gif',
  '.webp': 'image/webp',
  '.svg': 'image/svg+xml',
  // Documents
  '.pdf': 'application/pdf',
  '.doc': 'application/msword',
  '.docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  '.xls': 'application/vnd.ms-excel',
  '.xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  '.ppt': 'application/vnd.ms-powerpoint',
  '.pptx': 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
  // Text
  '.txt': 'text/plain',
  '.csv': 'text/csv',
  '.md': 'text/markdown',
  // Archives
  '.zip': 'application/zip',
};

/**
 * Get MIME type from filename extension as fallback
 */
export function getMimeTypeFromExtension(filename: string): string | null {
  const ext = filename.toLowerCase().slice(filename.lastIndexOf('.'));
  return EXTENSION_TO_MIME[ext] || null;
}

