    94	/**
    95	 * Handle image upload and insertion into editor
    96	 */
    97	async function handleImageUpload(
    98	  editor: Editor,
    99	  file: File,
   100	  options: ImageUploadOptions
   101	) {
   102	  const signal = options.abortController?.signal;
   103	
   104	  // Check if already aborted (e.g., user navigated away before upload started)
   105	  if (signal?.aborted) {
   106	    return;
   107	  }
   108	
   109	  options.onUploadStart?.(file);
   110	
   111	  // Generate unique upload ID for tracking navigation warnings
   112	  const uploadId = crypto.randomUUID();
   113	  registerUpload(uploadId, file.name);
   114	
   115	  // Create a data URL for immediate preview
   116	  const dataUrl = await fileToDataUrl(file);
   117	
   118	  // Check again after async operation
   119	  if (signal?.aborted) {
   120	    return;
   121	  }
   122	
   123	  // Insert image with data URL for immediate preview
   124	  editor
   125	    .chain()
   126	    .focus()
   127	    .setImage({
   128	      src: dataUrl,
   129	      alt: file.name,
   130	      title: file.name,
   131	    })
   132	    .run();
   133	
   134	  try {
   135	    const result = await uploadFile(
   136	      file,
   137	      (progress) => {
   138	        // Update global tracker for navigation warning
   139	        updateUploadProgress(uploadId, progress.progress);
   140	      },
   141	      signal
   142	    );
   143	
   144	    // Check if aborted before updating the editor
   145	    // This prevents updating a stale editor after navigation
   146	    if (signal?.aborted) {
   147	      console.log('Image upload completed but was cancelled - not updating editor');
   148	      return;
   149	    }
   150	
   151	    // Replace the data URL with the CDN URL
   152	    // Find and update the image node with matching src
   153	    const { state, view } = editor;
   154	    const { doc } = state;
   155	
   156	    let imagePos: number | null = null;
   157	
   158	    doc.descendants((node: ProseMirrorNode, pos: number) => {
   159	      if (node.type.name === 'image' && node.attrs.src === dataUrl) {
   160	        imagePos = pos;
   161	        return false; // Stop searching
   162	      }
   163	      return true;
   164	    });
   165	
   166	    if (imagePos !== null) {
   167	      // Update the image src to CDN URL
   168	      const transaction = state.tr.setNodeMarkup(imagePos, undefined, {
   169	        ...doc.nodeAt(imagePos)?.attrs,
   170	        src: result.cdnUrl.startsWith('http')
   171	          ? result.cdnUrl
   172	          : result.cdnUrl, // Relative URLs work via Vite proxy
   173	      });
   174	      view.dispatch(transaction);
   175	    }
   176	
   177	    // Upload complete - unregister from tracker
   178	    unregisterUpload(uploadId);
   179	    options.onUploadComplete?.(result.cdnUrl);
   180	  } catch (error) {
   181	    // Upload failed - unregister from tracker
   182	    unregisterUpload(uploadId);
   183	    // Don't report cancellation as an error - it's intentional
   184	    if (error instanceof DOMException && error.name === 'AbortError') {
   185	      console.log('Image upload cancelled');
   186	      return;
   187	    }
   188	
   189	    console.error('Image upload failed:', error);
   190	    options.onUploadError?.(
   191	      error instanceof Error ? error : new Error('Upload failed')
   192	    );
   193	
   194	    // Optionally remove the failed image or show error state
   195	    // For now, leave the data URL as fallback
   196	  }
   197	}
   198	
   199	/**
   200	 * Convert a File to a data URL
   201	 */
   202	function fileToDataUrl(file: File): Promise<string> {
   203	  return new Promise((resolve, reject) => {
   204	    const reader = new FileReader();
   205	    reader.onload = () => resolve(reader.result as string);
   206	    reader.onerror = reject;
   207	    reader.readAsDataURL(file);
   208	  });
   209	}
   210	
   211	/**
   212	 * Trigger file picker for image upload
   213	 */
   214	export function triggerImageUpload(
   215	  editor: Editor,
   216	  options: ImageUploadOptions = {}
   217	) {
   218	  // Check if already aborted
   219	  if (options.abortController?.signal?.aborted) {
   220	    return;
   221	  }
   222	
   223	  const input = document.createElement('input');
   224	  input.type = 'file';
   225	  input.accept = 'image/*';
   226	  input.multiple = true;
   227	
   228	  input.onchange = () => {
   229	    // Check again in case it was aborted while file picker was open
   230	    if (options.abortController?.signal?.aborted) {
   231	      return;
   232	    }
   233	    const files = Array.from(input.files || []);
   234	    files.forEach((file) => {
   235	      handleImageUpload(editor, file, options);
   236	    });
   237	  };
   238	
   239	  input.click();
   240	}
