    36	/**
    37	 * Get CSRF token for API requests
    38	 */
    39	async function getCsrfToken(): Promise<string> {
    40	  const res = await fetch(`${API_BASE}/api/csrf-token`, { credentials: 'include' });
    41	  if (!res.ok) throw new Error('Failed to get CSRF token');
    42	  const { token } = await res.json();
    43	  return token;
    44	}
