    46	export async function requestUpload(file: File, signal?: AbortSignal): Promise<UploadRequest> {
    47	  if (signal?.aborted) {
    48	    throw new DOMException('Upload cancelled', 'AbortError');
    49	  }
    50	
    51	  const csrfToken = await getCsrfToken();
    52	  const effectiveMimeType = file.type || getMimeTypeFromExtension(file.name) || 'application/octet-stream';
    53	  const res = await fetch(`${API_BASE}/api/files/upload-request`, {
    54	    method: 'POST',
    55	    headers: {
    56	      'Content-Type': 'application/json',
    57	      'x-csrf-token': csrfToken,
    58	    },
    59	    credentials: 'include',
    60	    body: JSON.stringify({
    61	      filename: file.name,
    62	      mimeType: effectiveMimeType,
    63	      sizeBytes: file.size,
    64	    }),
    65	    signal,
    66	  });
    67	
    68	  if (!res.ok) {
    69	    const error = await res.json().catch(() => ({}));
    70	    throw new Error(error.error || 'Failed to create upload request');
    71	  }
    72	
    73	  return res.json();
    74	}
    75	
    76	export async function uploadFile(
    77	  file: File,
    78	  onProgress?: ProgressCallback,
    79	  signal?: AbortSignal
    80	): Promise<UploadResult> {
    81	  if (signal?.aborted) {
    82	    throw new DOMException('Upload cancelled', 'AbortError');
    83	  }
    84	
    85	  const progress: UploadProgress = { fileId: '', progress: 0, status: 'pending' };
    86	  const updateProgress = (updates: Partial<UploadProgress>) => {
    87	    Object.assign(progress, updates);
    88	    onProgress?.({ ...progress });
    89	  };
    90	
    91	  try {
    92	    updateProgress({ status: 'pending', progress: 10 });
    93	    const request = await requestUpload(file, signal);
    94	    updateProgress({ fileId: request.fileId, progress: 20 });
    95	    updateProgress({ status: 'uploading', progress: 30 });
    96	
    97	    const fileBuffer = await file.arrayBuffer();
    98	    const isLocalUpload = request.uploadType === 'local' || request.uploadUrl.startsWith('/api/files/');
    99	    const fullUploadUrl = request.uploadUrl.startsWith('/api/files/') ? `${API_BASE}${request.uploadUrl}` : request.uploadUrl;
   100	
   101	    if (isLocalUpload) {
   102	      const uploadRes = await fetch(fullUploadUrl, {
   103	        method: request.method || 'POST',
   104	        headers: {
   105	          ...(request.headers ?? {}),
   106	          'Content-Type': file.type || getMimeTypeFromExtension(file.name) || 'application/octet-stream',
   107	        },
   108	        credentials: 'include',
   109	        body: fileBuffer,
   110	        signal,
   111	      });
   112	
   113	      if (!uploadRes.ok) {
   114	        const error = await uploadRes.json().catch(() => ({}));
   115	        throw new Error(error.error || 'Failed to upload file');
   116	      }
   117	
   118	      updateProgress({ progress: 90, status: 'complete' });
   119	      const fileRes = await fetch(`${API_BASE}/api/files/${request.fileId}`, { credentials: 'include', signal });
   120	      if (!fileRes.ok) throw new Error('Failed to get file metadata');
   121	      const fileData = await fileRes.json();
   122	      updateProgress({ progress: 100 });
   123	      return { fileId: request.fileId, cdnUrl: fileData.cdn_url };
   124	    }
   125	
   126	    const uploadRes = await fetch(fullUploadUrl, {
   127	      method: request.method || 'PUT',
   128	      headers: {
   129	        ...(request.headers ?? {}),
   130	        'Content-Type': file.type || getMimeTypeFromExtension(file.name) || 'application/octet-stream',
   131	      },
   132	      body: fileBuffer,
   133	      signal,
   134	    });
   135	
   136	    if (!uploadRes.ok) {
   137	      throw new Error('Failed to upload to S3');
   138	    }
   139	
   140	    updateProgress({ status: 'confirming', progress: 80 });
   141	    const confirmRes = await fetch(`${API_BASE}/api/files/${request.fileId}/confirm`, {
   142	      method: 'POST',
   143	      headers: { 'x-csrf-token': await getCsrfToken() },
   144	      credentials: 'include',
   145	      signal,
   146	    });
   147	
   148	    if (!confirmRes.ok) {
   149	      const error = await confirmRes.json().catch(() => ({}));
   150	      throw new Error(error.error || 'Failed to confirm upload');
   151	    }
   152	
   153	    const { cdnUrl } = await confirmRes.json();
   154	    updateProgress({ status: 'complete', progress: 100 });
   155	    return { fileId: request.fileId, cdnUrl };
   156	  } catch (error) {
   157	    updateProgress({ status: 'error', error: error instanceof Error ? error.message : 'Upload failed' });
   158	    throw error;
   159	  }
   160	}
