     8	
     9	/**
    10	 * Groups comments by their comment_id (thread identifier).
    11	 * Returns a map of commentId -> array of comments (root + replies).
    12	 */
    13	function groupByThread(comments: Comment[]): Map<string, Comment[]> {
    14	  const threads = new Map<string, Comment[]>();
    15	  for (const comment of comments) {
    16	    const existing = threads.get(comment.comment_id) || [];
    17	    existing.push(comment);
    18	    threads.set(comment.comment_id, existing);
    19	  }
    20	  return threads;
    21	}
    22	
    23	/**
    24	 * Find all comment mark positions in the document.
    25	 * Returns a map of commentId -> end position of the containing block.
    26	 */
    27	function findCommentPositions(doc: ProseMirrorNode): Map<string, number> {
    28	  const positions = new Map<string, number>();
    29	
    30	  doc.descendants((node: ProseMirrorNode, pos: number) => {
    31	    if (node.isText) {
    32	      for (const mark of node.marks) {
    33	        if (mark.type.name === 'commentMark' && mark.attrs.commentId) {
    34	          const commentId = mark.attrs.commentId;
    35	          // Always overwrite — doc.descendants iterates in document order,
    36	          // so the last block containing the mark wins.
    37	          const $pos = doc.resolve(pos);
    38	          const blockEnd = $pos.end(Math.max(1, $pos.depth));
    39	          positions.set(commentId, blockEnd);
    40	        }
    41	      }
    42	    }
    43	  });
    44	
    45	  return positions;
    46	}
