   133	/**
   134	 * CommentDisplay extension - Renders inline comment threads as widget decorations.
   135	 *
   136	 * Comments appear as bordered cards between content blocks, pushing content down
   137	 * (like GitHub code review). The extension reads comment data from its storage,
   138	 * which is updated by the parent Editor component via React Query.
   139	 */
   140	export const CommentDisplayExtension = Extension.create<Record<string, never>, CommentDisplayStorage>({
   141	  name: 'commentDisplay',
   142	
   143	  addStorage() {
   144	    return {
   145	      comments: [],
   146	      onReply: null,
   147	      onResolve: null,
   148	      pendingCommentId: null,
   149	      onSubmitComment: null,
   150	      onCancelComment: null,
