   155	    const storage = this.storage;
   156	
   157	    return [
   158	      new Plugin({
   159	        key: commentDisplayPluginKey,
   160	        props: {
   161	          decorations: (state) => {
   162	            const { doc } = state;
   163	            const comments = storage.comments;
   164	            const positions = findCommentPositions(doc);
   165	            const decorations: Decoration[] = [];
   166	
   167	            // Add pending comment input widget (before saved comments so it renders inline)
   168	            const pendingId = storage.pendingCommentId;
