   173	                  const container = document.createElement('div');
   174	                  container.className = 'comment-thread-inline comment-pending-input';
   175	                  container.contentEditable = 'false';
   176	                  container.innerHTML = `
   177	                    <div class="comment-pending-label">Add your comment:</div>
   178	                    <input type="text" class="comment-pending-field" placeholder="Write a comment..." data-pending-comment-id="${escapeHtml(pendingId)}" />
   179	                    <div class="comment-pending-hint">Press Enter to submit, Escape to cancel</div>
   180	                  `;
   181	                  // Auto-focus the input after it's added to the DOM
   182	                  requestAnimationFrame(() => {
   183	                    const input = container.querySelector('.comment-pending-field') as HTMLInputElement;
   184	                    input?.focus();
   185	                  });
   186	                  return container;
   187	                }, {
   188	                  side: 1,
   189	                  key: `pending-comment-${pendingId}`,
   190	                });
   191	                decorations.push(pendingWidget);
   192	              }
   193	            }
   194	
   195	            if (!comments || comments.length === 0) {
   196	              return DecorationSet.create(doc, decorations);
   197	            }
   198	
   199	            const threads = groupByThread(comments);
   200	
