    35	    mutationFn: async (data: { comment_id: string; content: string; parent_id?: string }) => {
    36	      const response = await apiPost(`/api/documents/${documentId}/comments`, data);
    37	      if (!response.ok) throw new Error('Failed to create comment');
    38	      return response.json();
    39	    },
    40	    onSuccess: () => {
    41	      queryClient.invalidateQueries({ queryKey: ['comments', documentId] });
