    25	function groupCommentsByThread(comments: Comment[]): CommentThread[] {
    26	  const threads = new Map<string, Comment[]>();
    27	
    28	  for (const comment of comments) {
    29	    const existing = threads.get(comment.comment_id);
    30	    if (existing) {
    31	      existing.push(comment);
    32	    } else {
    33	      threads.set(comment.comment_id, [comment]);
    34	    }
    35	  }
    36	
    37	  return [...threads.entries()].map(([comment_id, threadComments]) => ({
    38	    comment_id,
    39	    comments: threadComments,
    40	  }));
    41	}
