    43	function invalidateComments(queryClient: ReturnType<typeof useQueryClient>, documentId: string) {
    44	  queryClient.invalidateQueries({ queryKey: ['comments', documentId] });
    45	  queryClient.invalidateQueries({ queryKey: ['document', documentId, 'comments'] });
