    52	      const response = await apiGet(`/api/documents/${documentId}/comments`);
    53	      if (!response.ok) throw new Error('Failed to fetch comments');
    54	      const comments = (await response.json()) as Comment[];
    55	      return groupCommentsByThread(comments);
    56	    },
    57	    enabled: !!documentId,
    58	  });
    59	}
