     3	 * Used by both React components (via subscription) and non-React code (TipTap plugins)
     4	 */
     5	
     6	interface UploadInfo {
     7	  id: string;
     8	  filename: string;
     9	  progress: number;
    10	}
    11	
    12	// Global state
    13	const activeUploads = new Map<string, UploadInfo>();
    14	const listeners = new Set<() => void>();
    15	
    16	/**
    17	 * Register a new upload
    18	 */
    19	export function registerUpload(id: string, filename: string): void {
    20	  activeUploads.set(id, { id, filename, progress: 0 });
    21	  notifyListeners();
    22	}
    23	
    24	/**
    25	 * Update upload progress
    26	 */
    27	export function updateUploadProgress(id: string, progress: number): void {
    28	  const upload = activeUploads.get(id);
    29	  if (upload) {
    30	    upload.progress = progress;
    31	    notifyListeners();
    32	  }
    33	}
    34	
    35	/**
    36	 * Unregister a completed/failed upload
    37	 */
    38	export function unregisterUpload(id: string): void {
    39	  activeUploads.delete(id);
    40	  notifyListeners();
    41	}
    42	
    43	/**
    44	 * Get current upload count
    45	 */
    46	export function getUploadCount(): number {
    47	  return activeUploads.size;
    48	}
    49	
    50	/**
    51	 * Get all active uploads
    52	 */
    53	export function getActiveUploads(): UploadInfo[] {
    54	  return Array.from(activeUploads.values());
    55	}
    56	
    57	/**
    58	 * Subscribe to upload changes (for React components)
    59	 */
    60	export function subscribeToUploads(listener: () => void): () => void {
    61	  listeners.add(listener);
    62	  return () => listeners.delete(listener);
    63	}
    64	
    65	function notifyListeners(): void {
    66	  listeners.forEach((listener) => listener());
    67	}
