    13	  uploadCount: number;
    14	  isUploading: boolean;
    15	  activeUploads: ReturnType<typeof getActiveUploads>;
    16	}
    17	
    18	const UploadContext = createContext<UploadContextValue | null>(null);
    19	
    20	export function UploadProvider({ children }: { children: ReactNode }) {
    21	  // Subscribe to global upload tracker using useSyncExternalStore
    22	  const uploadCount = useSyncExternalStore(
    23	    subscribeToUploads,
    24	    getUploadCount,
    25	    getUploadCount
