    28	  const activeUploads = useSyncExternalStore(
    29	    subscribeToUploads,
    30	    getActiveUploads,
    31	    getActiveUploads
    32	  );
    33	  const isUploading = uploadCount > 0;
    34	
    35	  // Browser beforeunload warning
    36	  useEffect(() => {
    37	    if (!isUploading) return;
